import{_ as o,o as r,c as i,a1 as n}from"./chunks/framework.BwbI10pK.js";const u=JSON.parse('{"title":"Browser Internals and Rendering","description":"","frontmatter":{},"headers":[],"relativePath":"en/browser/index.md","filePath":"en/browser/index.md"}'),t={name:"en/browser/index.md"};function a(s,e,l,d,c,p){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="browser-internals-and-rendering" tabindex="-1">Browser Internals and Rendering <a class="header-anchor" href="#browser-internals-and-rendering" aria-label="Permalink to &quot;Browser Internals and Rendering&quot;">​</a></h1><blockquote><p>Subtitle: From multi-process architecture to the rendering pipeline, build a complete mental model from request to pixel.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>When many frontend engineers approach performance optimization, their first reaction is to blame &quot;framework re-renders&quot; or &quot;bundle size,&quot; while ignoring the fact that the real bottleneck often lies inside the browser&#39;s own pipeline. This module does not treat the browser as a black box. Instead, it disassembles the network stack, HTML/CSS parsers, V8 engine, rendering pipeline, and GPU compositing so that you understand how every line of code finally becomes a pixel on the screen.</p><p>Only by building a complete mental model from request to pixel can you locate performance problems to a specific stage and choose the right optimization strategy.</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Multi-process architecture</strong>: Responsibilities of the browser process, renderer process, GPU process, and network process, plus IPC collaboration.</li><li><strong>Rendering pipeline</strong>: Cost and triggering conditions of the five stages — Style / Layout / Paint / Raster / Composite.</li><li><strong>Resource loading</strong>: Preload scanner, Fetch Priority, and how HTTP/2 / HTTP/3 change resource organization.</li><li><strong>GPU compositing</strong>: Layers, tile rasterization, compositing-layer promotion conditions, and compositing-layer explosion.</li><li><strong>Performance metrics</strong>: Breakdown and optimization directions for TTFB / LCP / INP / CLS.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/browser/rendering-pipeline">Rendering Pipeline: From HTML to Pixels</a> — A complete end-to-end overview; understand the input and output of each stage.</li><li><a href="/en/browser/layout-thrashing">The Truth About Layout Thrashing</a> — Causes of forced synchronous layout and the FastDOM solution.</li><li><a href="/en/browser/painting-rasterization">Painting and Rasterization</a> — Paint records, tile rasterization, and compositing-layer mechanisms.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Intermediate and senior frontend engineers who want to break free from the limited perspective of &quot;framework-level optimization.&quot;</li><li>Performance owners who need to build a team-level framework for diagnosing performance issues.</li><li>Frontend architects who need to evaluate browser capability boundaries during technical decision-making.</li></ul>',11)])])}const m=o(t,[["render",a]]);export{u as __pageData,m as default};
